export function updateTrace(id: string, req: UpdateTraceRequest): Trace | null {
  const db = getDatabase();
  const existing = getTraceById(id);           // line 177 — confirm still exists
  if (!existing) return null;

  const now = new Date().toISOString();
  const taskGoal = req.taskGoal ?? existing.taskGoal;
  const status = req.status ?? existing.status;  // line 184 — 'paused' is applied here

  // Merge affected_files: union of existing and new, deduplicated
  const mergedFiles = req.affectedFiles !== undefined
    ? [...new Set([...existing.affectedFiles, ...req.affectedFiles])]
    : existing.affectedFiles;

  db.prepare(`
    UPDATE traces
    SET task_goal = @task_goal,
        status    = @status,
        affected_files = @affected_files,
        updated_at = @updated_at
    WHERE id = @id
  `).run({                                    // lines 191–200 — parameterised SQLite UPDATE
    id,
    task_goal: taskGoal,
    status,
    affected_files: toJson(mergedFiles),
    updated_at: now,
  });

  return getTraceById(id);                    // line 202 — re-fetch and return updated trace
}
